input.command:
cat results.tsv | awk -F'\t' '
  /trivial.*mean.*-0\.000000/ && $2 != "crash" && NF > 1 {
    print "TRIVIAL:", $0
  }
  /mean.*1\.000218/ && $2 != "crash" && NF > 1 {
    print "POSITIVE:", $0
  }
  /mean.*-1\.000218/ && $2 != "crash" && NF > 1 {
    print "NEGATIVE:", $0
  }
' | sort -t: -k2 | tail -30

awk -F'\t' '$2 != "crash" && $2 != "residual" {
  mean=$4; residual=$2; 
  if (mean ~ /-?0\.000/) print "TRIVIAL: " residual " @ exp" $1;
  else if (mean ~ /1\.000/) print "POSITIVE: " residual " @ exp" $1;
  else if (mean ~ /-1\.000/) print "NEGATIVE: " residual " @ exp" $1;
}' results.tsv | sort -t' ' -k2 -g | head -15

awk -F'\t' '$2 != "crash" && $2 != "residual" {
  mean=$4; residual=$2; 
  if (mean ~ /-?0\.000/) print "TRIVIAL " residual " " $1;
  else if (mean ~ /1\.000/) print "POSITIVE " residual " " $1;
  else if (mean ~ /-1\.000/) print "NEGATIVE " residual " " $1;
}' results.tsv | sort -k1,1 -k2,2 -g | awk '{print $1 ": " $2 " @ exp" $3}' | tail -10
